package ru.memearena.media.application;
import org.slf4j.*; import org.springframework.scheduling.annotation.Scheduled; import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.media.infrastructure.MediaAssetRepository; import java.time.*;
@Service public class OrphanMediaCleanupService { private static final Logger log=LoggerFactory.getLogger(OrphanMediaCleanupService.class); private final MediaAssetRepository repo; private final MediaStorage storage; private final Clock clock; public OrphanMediaCleanupService(MediaAssetRepository repo,MediaStorage storage,Clock clock){this.repo=repo;this.storage=storage;this.clock=clock;} @Transactional public int cleanup(){int ok=0; for(var a: repo.findUnattachedActiveOlderThan(Instant.now(clock).minus(Duration.ofHours(24)))){try{a.markOrphaned(); repo.saveAndFlush(a); storage.delete(a.getStorageKey()); a.markDeleted(Instant.now(clock)); repo.save(a); ok++;}catch(Exception e){log.warn("Failed to delete orphan media {}",a.getId(),e);}} return ok;} @Scheduled(fixedDelayString="${media.cleanup.fixed-delay-ms:3600000}") @ConditionalOnProperty(name="media.cleanup.enabled",havingValue="true") public void scheduled(){cleanup();} }
